44: Rule::Rule(const ProtoRule& rule, Regex::Engine& regex_engine) : rule_(rule) {
45:   // Ensure only one of header and cookie is specified.
46:   // TODO(radha13): remove this once we are on v4 and these fields are folded into a oneof.
47:   if (!rule.cookie().empty() && !rule.header().empty()) {
48:     throw EnvoyException("Cannot specify both header and cookie");
49:   }
50: 
51:   // Initialize the shared pointer.
52:   if (!rule.header().empty()) {
53:     selector_ =
54:         std::make_shared<HeaderValueSelector>(Http::LowerCaseString(rule.header()), rule.remove());
55:   } else if (!rule.cookie().empty()) {
56:     selector_ = std::make_shared<CookieValueSelector>(rule.cookie());
57:   } else {
58:     throw EnvoyException("One of Cookie or Header option needs to be specified");
59:   }
60: 
61:   // Rule must have at least one of the `on_header_*` fields set.
62:   if (!rule.has_on_header_present() && !rule.has_on_header_missing()) {
63:     const auto& error = fmt::format("header to metadata filter: rule for {} has neither "
64:                                     "`on_header_present` nor `on_header_missing` set",
65:                                     selector_->toString());
66:     throw EnvoyException(error);
67:   }
68: 
69:   // Ensure value and regex_value_rewrite are not mixed.
70:   // TODO(rgs1): remove this once we are on v4 and these fields are folded into a oneof.
71:   if (!rule.on_header_present().value().empty() &&
72:       rule.on_header_present().has_regex_value_rewrite()) {
73:     throw EnvoyException("Cannot specify both value and regex_value_rewrite");
74:   }
75: 
76:   // Remove field is un-supported for cookie.
77:   if (!rule.cookie().empty() && rule.remove()) {
78:     throw EnvoyException("Cannot specify remove for cookie");
79:   }
80: 
81:   if (rule.has_on_header_missing() && rule.on_header_missing().value().empty()) {
82:     throw EnvoyException("Cannot specify on_header_missing rule with an empty value");
83:   }
84: 
85:   if (rule.on_header_present().has_regex_value_rewrite()) {
86:     const auto& rewrite_spec = rule.on_header_present().regex_value_rewrite();
87:     regex_rewrite_ =
88:         THROW_OR_RETURN_VALUE(Regex::Utility::parseRegex(rewrite_spec.pattern(), regex_engine),
89:                               Regex::CompiledMatcherPtr);
90:     regex_rewrite_substitution_ = rewrite_spec.substitution();
91:   }
92: }
