#include <memory>

#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "test/mocks/http/mocks.h"
#include "test/test_common/utility.h"

#include "gmock/gmock.h"
#include "gtest/gtest.h"

using testing::_;
using testing::NiceMock;
using testing::Return;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjectionFilter {
namespace {

class CustomHeaderInjectionTest : public testing::Test {
public:
  const std::string request_config_yaml = R"EOF(
request_headers:
  - name: x-injected-request
    value: request-value
response_headers:
  - name: x-injected-response
    value: response-value
)EOF";

  void initializeFilter(const std::string& yaml) {
    envoy::extensions::filters::http::custom_header_injection::v3::Config config;
    TestUtility::loadFromYaml(yaml, config);
    config_ = std::make_shared<Config>(config);
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config_);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  ConfigSharedPtr config_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
};

/**
 * Test request header injection.
 */
TEST_F(CustomHeaderInjectionTest, InjectRequestHeaders) {
  initializeFilter(request_config_yaml);
  Http::TestRequestHeaderMapImpl headers;

  auto status = filter_->decodeHeaders(headers, false);

  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(headers.get("x-injected-request"), "request-value");
}

/**
 * Test response header injection.
 */
TEST_F(CustomHeaderInjectionTest, InjectResponseHeaders) {
  initializeFilter(request_config_yaml);
  Http::TestResponseHeaderMapImpl headers;

  auto status = filter_->encodeHeaders(headers, false);

  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(headers.get("x-injected-response"), "response-value");
}

/**
 * Test that filter continues processing when no headers are configured.
 */
TEST_F(CustomHeaderInjectionTest, EmptyConfig) {
  const std::string empty_config_yaml = R"EOF(
)EOF";
  initializeFilter(empty_config_yaml);
  Http::TestRequestHeaderMapImpl req_headers;
  Http::TestResponseHeaderMapImpl resp_headers;

  auto req_status = filter_->decodeHeaders(req_headers, false);
  auto resp_status = filter_->encodeHeaders(resp_headers, false);

  EXPECT_EQ(req_status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(resp_status, Http::FilterHeadersStatus::Continue);
}

/**
 * Test multiple header injection.
 */
TEST_F(CustomHeaderInjectionTest, MultipleHeaders) {
  const std::string multi_header_yaml = R"EOF(
request_headers:
  - name: x-header-1
    value: value-1
  - name: x-header-2
    value: value-2
response_headers:
  - name: x-response-1
    value: response-1
  - name: x-response-2
    value: response-2
)EOF";
  initializeFilter(multi_header_yaml);
  Http::TestRequestHeaderMapImpl req_headers;
  Http::TestResponseHeaderMapImpl resp_headers;

  filter_->decodeHeaders(req_headers, false);
  filter_->encodeHeaders(resp_headers, false);

  EXPECT_EQ(req_headers.get("x-header-1"), "value-1");
  EXPECT_EQ(req_headers.get("x-header-2"), "value-2");
  EXPECT_EQ(resp_headers.get("x-response-1"), "response-1");
  EXPECT_EQ(resp_headers.get("x-response-2"), "response-2");
}

} // namespace
} // namespace CustomHeaderInjectionFilter
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

